use super::*;

#[derive(Debug, Parser)]
#[command(version = elf_cli::VERSION, rename_all = "kebab", styles = elf_cli::styles())]
pub(super) struct Args {
	/// Base ELF config to load before Docker runtime overrides are applied.
	#[arg(long, short = 'c', value_name = "FILE")]
	pub(super) config: PathBuf,

	/// Directory containing the generated benchmark corpus markdown files.
	#[arg(long, value_name = "DIR")]
	pub(super) corpus: PathBuf,

	/// Query manifest generated by the live-baseline harness.
	#[arg(long, value_name = "FILE")]
	pub(super) queries: PathBuf,

	/// Write ELF result JSON to this file.
	#[arg(long, value_name = "FILE")]
	pub(super) out: PathBuf,
}

#[derive(Debug, Deserialize)]
pub(super) struct QueryManifest {
	pub(super) queries: Vec<QueryCase>,
}

#[derive(Clone, Debug, Deserialize, Serialize)]
pub(super) struct QueryCase {
	pub(super) id: String,
	pub(super) task: Option<String>,
	pub(super) query: String,
	pub(super) expected_doc: String,
	pub(super) expected_terms: Vec<String>,
	#[serde(default)]
	pub(super) allowed_alternate_docs: Vec<String>,
	#[serde(default)]
	pub(super) expected_evidence_ids: Vec<String>,
	#[serde(default)]
	pub(super) allowed_alternate_evidence_ids: Vec<String>,
}
impl QueryCase {
	pub(super) fn generated(
		id: String,
		query: String,
		expected_doc: String,
		expected_terms: Vec<String>,
	) -> Self {
		Self {
			id,
			task: None,
			query,
			expected_evidence_ids: vec![evidence_id_for_doc(&expected_doc)],
			allowed_alternate_docs: Vec::new(),
			allowed_alternate_evidence_ids: Vec::new(),
			expected_doc,
			expected_terms,
		}
	}
}

